#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cuda_runtime.h>
#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_gpu_opencl_wrapper.h"

#define THREADS_PER_BLOCK 1024

__global__ void findK_kernel(	long height,
								knode *knodesD,
								long knodes_elem,
								record *recordsD,

								long *currKnodeD,
								long *offsetD,
								int *keysD, 
								record *ansD,
								int order)
{
	int thid = threadIdx.x;
	int bid = blockIdx.x;

	if (thid >= order) return;

	for(int i = 0; i < height; i++){
		if((knodesD[currKnodeD[bid]].keys[thid]) <= keysD[bid] && (knodesD[currKnodeD[bid]].keys[thid+1] > keysD[bid])){
			if(knodesD[offsetD[bid]].indices[thid] < knodes_elem){
				offsetD[bid] = knodesD[offsetD[bid]].indices[thid];
			}
		}
		__syncthreads();
		if(thid==0){
			currKnodeD[bid] = offsetD[bid];
		}
		__syncthreads();
	}

	if(knodesD[currKnodeD[bid]].keys[thid] == keysD[bid]){
		ansD[bid].value = recordsD[knodesD[currKnodeD[bid]].indices[thid]].value;
	}
}

extern "C" void 
kernel_gpu_cuda_wrapper(record *records,
						long records_mem,
						knode *knodes,
						long knodes_elem,
						long knodes_mem,

						int order,
						long maxheight,
						int count,

						long *currKnode,
						long *offset,
						int *keys,
						record *ans)
{
	knode *d_knodes;
	record *d_records;
	long *d_currKnode;
	long *d_offset;
	int *d_keys;
	record *d_ans;

	cudaMalloc((void**)&d_knodes, knodes_mem);
	cudaMalloc((void**)&d_records, records_mem);
	cudaMalloc((void**)&d_currKnode, count * sizeof(long));
	cudaMalloc((void**)&d_offset, count * sizeof(long));
	cudaMalloc((void**)&d_keys, count * sizeof(int));
	cudaMalloc((void**)&d_ans, count * sizeof(record));

	cudaMemcpy(d_knodes, knodes, knodes_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_records, records, records_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_currKnode, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
	cudaMemcpy(d_offset, offset, count * sizeof(long), cudaMemcpyHostToDevice);
	cudaMemcpy(d_keys, keys, count * sizeof(int), cudaMemcpyHostToDevice);
	cudaMemcpy(d_ans, ans, count * sizeof(record), cudaMemcpyHostToDevice);

	int threads = order < THREADS_PER_BLOCK ? order : THREADS_PER_BLOCK;
	int blocks = count;

	findK_kernel<<<blocks, threads>>>(maxheight, d_knodes, knodes_elem, d_records, d_currKnode, d_offset, d_keys, d_ans, order);
	cudaDeviceSynchronize();

	cudaMemcpy(ans, d_ans, count * sizeof(record), cudaMemcpyDeviceToHost);

	cudaFree(d_knodes);
	cudaFree(d_records);
	cudaFree(d_currKnode);
	cudaFree(d_offset);
	cudaFree(d_keys);
	cudaFree(d_ans);
}

