	cudaMemcpy(d_start, start, count * sizeof(int), cudaMemcpyHostToDevice);
	cudaMemcpy(d_end, end, count * sizeof(int), cudaMemcpyHostToDevice);
	cudaMemcpy(d_recstart, recstart, count * sizeof(int), cudaMemcpyHostToDevice);
